#include "interface.h"

#include "xxhash.h"

#include <cstdint>
#include <string>

namespace {
constexpr std::size_t kChunkSize = 1 << 10;
}

uint64_t chunked_hash(const std::string& input) {
  uint64_t acc = 0;
  const char* data = input.data();
  const std::size_t size = input.size();
  std::size_t offset = 0;

  // Process chunks without any string allocation
  while (offset < size) {
    const std::size_t remaining = size - offset;
    const std::size_t take = remaining < kChunkSize ? remaining : kChunkSize;

    // Prefetch next chunk
    if (offset + kChunkSize < size) {
      __builtin_prefetch(data + offset + kChunkSize, 0, 3);
    }

    acc ^= XXH3_64bits(data + offset, take);
    acc = (acc << 1) | (acc >> 63);
    offset += kChunkSize;
  }
  return acc;
}
